body.query:
query Applications($input: ApplicationsInput!, $nationalitiesInput2: ApplicationProfileNationalitiesInput!, $displayLabelInput2: CandidateProfileRightToWorkDisplayLabelInput!, $countryNameInput2: CandidateProfileNationalityCountryNameInput!, $displayDescriptionInput2: LocationDisplayDescriptionInput!) {
  applications(input: $input) {
    ... on ApplicationsResponseSuccess {
      result {
        ...application
        __typename
      }
      pageInfo {
        pageNumber
        pageSize
        total
        totalPages
        __typename
      }
      __typename
    }
    ... on ResponseError {
      error
      __typename
    }
    __typename
  }
}

fragment application on Application {
  id
  adcentreCandidateId
  adcentreProspectId
  candidateId
  applicationId
  firstName
  lastName
  email
  phone
  mostRecentJobTitle
  mostRecentCompanyName
  mostRecentRoleMonths
  appliedDateUtc
  statusFolder
  isRead
  isPriorityApply
  metadata {
    ... on ApplicationMetadataResponseSuccess {
      result {
        emailCount
        noteCount
        hasResume
        hasCoverLetter
        hasSelectionCriteria
        __typename
      }
      __typename
    }
    ... on ResponseError {
      error
      __typename
    }
    __typename
  }
  candidateStats {
    ... on ApplicationCandidateStatsResponseSuccess {
      result {
        totalApplicationCount
        __typename
      }
      __typename
    }
    ... on ResponseError {
      error
      __typename
    }
    __typename
  }
  rating {
    rating
    __typename
  }
  source
  billableStatus
  matchedQualities {
    id
    isTop
    displayLabel
    relevanceScore
    __typename
  }
  attachmentsV2 {
    ... on ApplicationAttachmentsV2ResponseSuccess {
      result {
        attachmentId
        attachmentType
        hasConvertedPdf
        fileName
        __typename
      }
      __typename
    }
    ... on ResponseError {
      error
      __typename
    }
    __typename
  }
  verifications {
    ... on ApplicationVerificationsResponseSuccess {
      result {
        title
        viewFields {
          label
          value
          __typename
        }
        __typename
      }
      __typename
    }
    ... on ResponseError {
      error
      __typename
    }
    __typename
  }
  questionnaireSubmission {
    ... on ApplicationQuestionnaireSubmissionResponseSuccess {
      result {
        id
        questions {
          id
          legacyId
          text
          answers {
            id
            legacyId
            text
            verification {
              title
              viewFields {
                label
                value
                __typename
              }
              __typename
            }
            __typename
          }
          status
          answerType
          source
          __typename
        }
        __typename
      }
      __typename
    }
    ... on ResponseError {
      error
      __typename
    }
    __typename
  }
  profile {
    ... on ResponseError {
      error
      __typename
    }
    ... on ApplicationProfileResponseSuccess {
      result {
        education {
          id
          name
          completed
          completionDate {
            year
            month
            __typename
          }
          highlights
          institute
          credential {
            name
            values
            __typename
          }
          verification {
            title
            viewFields {
              label
              value
              __typename
            }
            __typename
          }
          __typename
        }
        licences {
          id
          name
          issuingOrganisation
          issueDate {
            month
            year
            __typename
          }
          expiryDate {
            month
            year
            __typename
          }
          noExpiryDate
          description
          formattedExpiryDate
          credential {
            name
            values
            __typename
          }
          verification {
            title
            viewFields {
              label
              value
              __typename
            }
            __typename
          }
          __typename
        }
        skills {
          keyword
          __typename
        }
        workHistory {
          id
          title
          company
          startDate {
            month
            year
            __typename
          }
          endDate {
            month
            year
            __typename
          }
          achievements
          __typename
        }
        rightsToWork {
          country
          answer
          __typename
        }
        rightsToWorkV2 {
          id
          displayLabel(input: $displayLabelInput2)
          __typename
        }
        verificationsStats {
          ... on ApplicationProfileVerificationsStatsSuccess {
            totalCount
            __typename
          }
          ... on ResponseError {
            error
            __typename
          }
          __typename
        }
        verifications {
          ... on ApplicationProfileVerificationsSuccess {
            result {
              verifiedIdentity {
                viewFields {
                  label
                  value
                  __typename
                }
                __typename
              }
              workHistory {
                title
                __typename
              }
              education {
                title
                __typename
              }
              licences {
                title
                __typename
              }
              rightToWork {
                title
                __typename
              }
              __typename
            }
            __typename
          }
          ... on ResponseError {
            error
            __typename
          }
          __typename
        }
        homeLocation {
          id
          displayDescription(input: $displayDescriptionInput2)
          __typename
        }
        nationalities(input: $nationalitiesInput2) {
          ... on ResponseError {
            error
            __typename
          }
          ... on ApplicationProfileNationalitiesResponseSuccess {
            result {
              id
              countryName(input: $countryNameInput2)
              __typename
            }
            __typename
          }
          __typename
        }
        referenceChecksStats {
          ... on ApplicationProfileReferenceChecksStatsResponseSuccess {
            result {
              ... on ApplicationProfileReferenceChecksStatsRequested {
                __typename
                referenceCheckType
              }
              ... on ApplicationProfileReferenceChecksStatsAvailable {
                referenceCheckType
                finishedCount
                totalCount
                __typename
              }
              __typename
            }
            __typename
          }
          __typename
        }
        __typename
      }
      __typename
    }
    __typename
  }
  fit {
    ... on ApplicationFitResponseSuccess {
      result {
        summaryV2
        __typename
      }
      __typename
    }
    ... on ResponseError {
      __typename
    }
    __typename
  }
  fitLevelV2
  candidateHighlights {
    ... on ApplicationCandidateHighlightsResponseSuccess {
      result {
        highlights
        id
        __typename
      }
      __typename
    }
    ... on ResponseError {
      error
      __typename
    }
    __typename
  }
  __typename
}
